package markets

import "errors"

func newDomainError(message string) error {
	return errors.New(message)
}

var (
	// ErrMarketNotFound indicates that the requested market does not exist.
	ErrMarketNotFound = newDomainError("market not found")
	// ErrInvalidQuestionTitle indicates that the market question title is invalid.
	ErrInvalidQuestionTitle = newDomainError("invalid question title")
	// ErrInvalidQuestionLength indicates that the market question title is blank or too long.
	ErrInvalidQuestionLength = newDomainError("question title exceeds maximum length or is blank")
	// ErrInvalidDescriptionLength indicates that the market description is too long.
	ErrInvalidDescriptionLength = newDomainError("question description exceeds maximum length")
	// ErrInvalidLabel indicates that one or more custom labels are invalid.
	ErrInvalidLabel = newDomainError("invalid label")
	// ErrInvalidResolutionTime indicates that the supplied resolution time is invalid.
	ErrInvalidResolutionTime = newDomainError("invalid market resolution time")
	// ErrUserNotFound indicates that the referenced creator user does not exist.
	ErrUserNotFound = newDomainError("creator user not found")
	// ErrInsufficientBalance indicates that the actor does not have enough balance.
	ErrInsufficientBalance = newDomainError("insufficient balance")
	// ErrUnauthorized indicates that the actor is not allowed to perform the action.
	ErrUnauthorized = newDomainError("unauthorized")
	// ErrInvalidInput indicates that one or more request inputs are invalid.
	ErrInvalidInput = newDomainError("invalid input")
	// ErrInvalidState indicates that the market state does not allow the requested action.
	ErrInvalidState = newDomainError("invalid state")
)

// IsMarketNotFound reports whether err represents a missing market.
func IsMarketNotFound(err error) bool {
	return errors.Is(err, ErrMarketNotFound)
}

// IsInvalidInput reports whether err represents invalid caller input.
func IsInvalidInput(err error) bool {
	return errors.Is(err, ErrInvalidInput)
}

// IsUnauthorized reports whether err represents an authorization failure.
func IsUnauthorized(err error) bool {
	return errors.Is(err, ErrUnauthorized)
}

// IsInvalidState reports whether err represents an invalid market state transition.
func IsInvalidState(err error) bool {
	return errors.Is(err, ErrInvalidState)
}

package markets

import (
	"strings"
	"time"

	"socialpredict/models"
)

// Market represents the core market domain model
type Market struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	ResolutionResult        string
	CreatorUsername         string
	YesLabel                string
	NoLabel                 string
	Status                  string
	CreatedAt               time.Time
	UpdatedAt               time.Time
	InitialProbability      float64
	UTCOffset               int
}

// CreatedBy reports whether the market belongs to the supplied creator username.
func (m *Market) CreatedBy(username string) bool {
	if m == nil {
		return false
	}
	return strings.TrimSpace(m.CreatorUsername) == strings.TrimSpace(username)
}

// IsResolved reports whether the market is in the resolved state.
func (m *Market) IsResolved() bool {
	if m == nil {
		return false
	}
	return strings.EqualFold(strings.TrimSpace(m.Status), "resolved")
}

// MarketCreateRequest represents the request to create a new market
type MarketCreateRequest struct {
	QuestionTitle      string
	Description        string
	OutcomeType        string
	ResolutionDateTime time.Time
	YesLabel           string
	NoLabel            string
}

// HasCustomLabels reports whether the create request includes either custom label.
func (r MarketCreateRequest) HasCustomLabels() bool {
	return strings.TrimSpace(r.YesLabel) != "" || strings.TrimSpace(r.NoLabel) != ""
}

// UserPosition represents a user's holdings within a market.
type UserPosition struct {
	Username         string
	MarketID         int64
	YesSharesOwned   int64
	NoSharesOwned    int64
	Value            int64
	TotalSpent       int64
	TotalSpentInPlay int64
	IsResolved       bool
	ResolutionResult string
}

// MarketPositions aggregates user positions for a market.
type MarketPositions []*UserPosition

// Normalize returns a non-nil collection for callers that treat empty and nil identically.
func (p MarketPositions) Normalize() MarketPositions {
	if p == nil {
		return MarketPositions{}
	}
	return p
}

// Bet represents a wager placed within a market.
type Bet struct {
	ID        uint
	Username  string
	MarketID  uint
	Amount    int64
	Outcome   string
	PlacedAt  time.Time
	CreatedAt time.Time
}

// ToModelBet converts the domain bet into the shared model shape used by math services.
func (b Bet) ToModelBet() models.Bet {
	return models.Bet{
		Username: b.Username,
		MarketID: b.MarketID,
		Amount:   b.Amount,
		Outcome:  b.Outcome,
		PlacedAt: b.PlacedAt,
	}
}

// ToModelBets converts a domain bet slice into the shared model representation.
func ToModelBets(bets []*Bet) []models.Bet {
	if len(bets) == 0 {
		return []models.Bet{}
	}

	modelBets := make([]models.Bet, len(bets))
	for i, bet := range bets {
		if bet == nil {
			continue
		}
		modelBets[i] = bet.ToModelBet()
	}

	return modelBets
}

// PayoutPosition captures the resolved valuation per user for distribution.
type PayoutPosition struct {
	Username string
	Value    int64
}

// IsPayable reports whether the payout position results in a positive transfer.
func (p *PayoutPosition) IsPayable() bool {
	return p != nil && p.Value > 0
}

// PublicMarket represents the public view of a market.
type PublicMarket struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	UTCOffset               int
	IsResolved              bool
	ResolutionResult        string
	InitialProbability      float64
	CreatorUsername         string
	CreatedAt               time.Time
	YesLabel                string
	NoLabel                 string
}

// Resolved reports whether the public market already has a terminal resolution.
func (m *PublicMarket) Resolved() bool {
	return m != nil && m.IsResolved
}

// FromMarket copies the public fields from a domain market into the public view model.
func (m *PublicMarket) FromMarket(market *Market) *PublicMarket {
	if market == nil {
		return nil
	}

	if m == nil {
		m = &PublicMarket{}
	}

	*m = PublicMarket{
		ID:                      market.ID,
		QuestionTitle:           market.QuestionTitle,
		Description:             market.Description,
		OutcomeType:             market.OutcomeType,
		ResolutionDateTime:      market.ResolutionDateTime,
		FinalResolutionDateTime: market.FinalResolutionDateTime,
		UTCOffset:               market.UTCOffset,
		IsResolved:              market.IsResolved(),
		ResolutionResult:        market.ResolutionResult,
		InitialProbability:      market.InitialProbability,
		CreatorUsername:         market.CreatorUsername,
		CreatedAt:               market.CreatedAt,
		YesLabel:                market.YesLabel,
		NoLabel:                 market.NoLabel,
	}

	return m
}

