type fixedClock struct {
	nowFunc func() time.Time
}

func newFixedClock(now time.Time) fixedClock {
	return fixedClock{
		nowFunc: func() time.Time { return now },
	}
}

func (c fixedClock) Now() time.Time {
	if c.nowFunc == nil {
		return time.Time{}
	}
	return c.nowFunc()
}

